    always_comb begin
        fub_axi_arready = 1'b0;
        case (comb_slave_select_ar)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_arready = cpu_rd_32b_arready;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_arready = cpu_rd_32b_arready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // Read response MUX (R channel - uses r_slave_select FIFO head)
    always_comb begin
        fub_axi_rid = 4'd0;
        fub_axi_rdata = 32'd0;
        fub_axi_rresp = 2'b00;
        fub_axi_rlast = 1'b0;
        fub_axi_rvalid = 1'b0;

