                fub_axi_rid = cpu_rd_32b_r.id;
                fub_axi_rdata = cpu_rd_32b_r.data;
                fub_axi_rresp = cpu_rd_32b_r.resp;
                fub_axi_rlast = cpu_rd_32b_r.last;
                fub_axi_rvalid = cpu_rd_32b_rvalid;
